import React from 'react';
import { motion } from 'framer-motion';
import { Users, Award, Clock, Shield } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const AboutPage = () => {
  const { t } = useLanguage();

  const stats = [
    { number: '500+', label: '满意客户' },
    { number: '50+', label: '专业师傅' },
    { number: '24/7', label: '服务时间' },
    { number: '98%', label: '满意度' }
  ];

  const values = [
    {
      icon: Shield,
      title: '质量保证',
      description: '所有服务都有质量保证，确保您满意'
    },
    {
      icon: Clock,
      title: '快速响应',
      description: '24小时内响应您的服务需求'
    },
    {
      icon: Award,
      title: '专业团队',
      description: '经验丰富的专业师傅团队'
    },
    {
      icon: Users,
      title: '客户至上',
      description: '以客户需求为中心的服务理念'
    }
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-blue-600 to-purple-600 text-white py-16">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center"
          >
            <h1 className="text-4xl md:text-5xl font-bold mb-4">
              {t('aboutUs')}
            </h1>
            <p className="text-xl mb-8 max-w-2xl mx-auto">
              Swift Fix Pro 是新加坡领先的物业管理服务平台，致力于为客户提供专业、高效、可靠的维护服务。
            </p>
          </motion.div>
        </div>
      </section>

      {/* Stats Section */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
            {stats.map((stat, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                className="text-center"
              >
                <div className="text-3xl md:text-4xl font-bold text-blue-600 mb-2">
                  {stat.number}
                </div>
                <div className="text-gray-600">{stat.label}</div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Values Section */}
      <section className="py-16 bg-gray-50">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center mb-12"
          >
            <h2 className="text-3xl font-bold text-gray-900 mb-4">我们的价值观</h2>
            <p className="text-gray-600 max-w-2xl mx-auto">
              我们致力于通过专业服务和创新技术，为客户创造更好的物业管理体验。
            </p>
          </motion.div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {values.map((value, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                className="bg-white p-6 rounded-lg shadow-md text-center"
              >
                <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
                  <value.icon size={32} className="text-blue-600" />
                </div>
                <h3 className="text-xl font-semibold mb-2">{value.title}</h3>
                <p className="text-gray-600">{value.description}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Story Section */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4">
          <div className="max-w-4xl mx-auto">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
              className="text-center mb-12"
            >
              <h2 className="text-3xl font-bold text-gray-900 mb-4">我们的故事</h2>
              <p className="text-gray-600 text-lg leading-relaxed">
                Swift Fix Pro 成立于2020年，我们的使命是简化物业管理流程，让每个客户都能享受到专业、便捷的维护服务。
                通过整合优质供应商资源，我们为客户提供一站式解决方案，从日常维护到紧急维修，我们都能满足您的需求。
              </p>
            </motion.div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default AboutPage;
